#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
using namespace std;
struct wild_man{
    int st,yid,len;
}s[20];
int n,mx;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int exGCD(int a,int b,int &x,int &y){
    if(!b){x=1,y=0;return a;}
    int yu=exGCD(b,a%b,x,y);
    int tmp=x;x=y,y=tmp-a/b*y;
    return yu;
}
bool check(int m){
    for(int i=1;i<n;i++)
        for(int j=i+1;j<=n;j++){
            int a=s[i].yid-s[j].yid;
            int b=m,x=0,y=0;
            int c=s[j].st-s[i].st;
            int d=exGCD(a,b,x,y);
            if(c%d!=0)continue;
            a/=d,b/=d,c/=d;
            if(b<0)b=-b;
		    x=(x*c%b+b)%b;
		    if(x<=min(s[i].len,s[j].len))return 0;
        }
    return 1;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        s[i].st=read(),s[i].yid=read(),
        s[i].len=read(),mx=max(mx,s[i].st);
    for(int m=mx;m<=1000000;m++)
        if(check(m)){cout<<m<<"\n";break;}
    return 0;
}
